#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; ++i) {
        long long a, b;
        int op;
        scanf("%lld %lld %d", &a, &b, &op);
        switch (op) {
            case 1:
                printf("%lld\n", a + b);
                break;
            case 2:
                printf("%lld\n", a - b);
                break;
            case 3:
                printf("%lld\n", a * b);
                break;
            case 4:
                if (b == 0) {
                    printf("Division by zero error\n");
                } else {
                    long long q = a / b;
                    long long r = a % b;
                    printf("Quotient: %lld, Remainder: %lld\n", q, r);
                }
                break;
            case 5:
                printf("Exiting program.\n");
                break;
            default:
                printf("Operation does not exist - please provide the correct input\n");
        }
    }
    return 0;
}

