#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it))
        b = int(next(it))
        op = int(next(it))
        if op == 1:
            out.append(str(a + b))
        elif op == 2:
            out.append(str(a - b))
        elif op == 3:
            out.append(str(a * b))
        elif op == 4:
            if b == 0:
                out.append("Division by zero error")
            else:
                q = a // b
                r = a % b
                out.append(f"Quotient: {q}, Remainder: {r}")
        elif op == 5:
            out.append("Exiting program.")
        else:
            out.append("Operation does not exist - please provide the correct input")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

